	}

	if result.SessionID != "" {
		s := result.SessionID
		exec.SessionID = &s
	}
	workerID := firstNonEmptyStr(manifest.WorkerID, result.WorkerID)
	if workerID != "" {
		exec.WorkerID = &workerID
	}
	if result.StartedAt != "" {
		s := normalizeISOTime(result.StartedAt)
		exec.StartedAt = &s
	}
	if result.FinishedAt != "" {
		s := normalizeISOTime(result.FinishedAt)
		exec.FinishedAt = &s
	}
	if result.DurationMS > 0 {
		d := result.DurationMS
		exec.DurationMs = &d
	}
	if result.CostUSD != 0 {
		c := result.CostUSD
